from(bucket: "dba")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r["_measurement"] == "sqlserver_volume_space")
  |> filter(fn: (r) => r["_field"] == "used_space_bytes" or r["_field"] == "available_space_bytes")
  |> filter(fn: (r) => r["sql_instance"] == ${Instance:doublequote})
  |> filter(fn: (r) => r["host"] == ${host:doublequote})
  |> filter(fn: (r) => r["measurement_db_type"] == "SQLServer")
  |> aggregateWindow(every: v.windowPeriod, fn: mean, createEmpty: false)
  |> group(columns: ["volume_mount_point"])
  |> keep(columns: ["_time", "_field", "_value"])  // 필요한 열만 선택
  |> pivot(rowKey:["_time"], columnKey: ["_field"], valueColumn: "_value")
  |> map(fn: (r) => ({
      _time: r._time,
      // signal_wait_time_ms: r.signal_wait_time_ms, // difference(v: r.signal_wait_time_ms, nonNegative: true) / float(v: r._value_signal_wait_time_ms_count),  // delta 값 계산
      // wait_time_ms: r.wait_time_ms,
      space_used_percent:  (float(v: r.used_space_bytes) * 100.0) / float(v: r.available_space_bytes) 
    })
  )
  |> yield(name: "mean")

